import requests

def get_song_info(song_title):
    response = requests.get(f"https://api.music.example.com/songs?q={song_title}")
    if response.status_code == 200:
        data = response.json()
        for song in data.get('results', []):
            if song.get('title') == song_title:
                return {
                    'title': song.get('title'),
                    'artist': song.get('artist'),
                    'release_date': song.get('release_date')
                }
    return None

# Example usage
song_info = get_song_info("Archie, Marry Me")
print(song_info)
# Expected output: {'title': 'Archie, Marry Me', 'artist': 'Alvvays', 'release_date': '2013-04-06'}
